        {lead.service&&<span style={{...S.bdg,background:"#1E293B",color:"#94A3B8"}}>{lead.service}</span>}
        {lead.temperature&&lead.status==="in_progress"&&<span>{TEMPS.find(t=>t.id===lead.temperature)?.emoji}</span>}
